class Solution {
public:
    string concatHex36(int n) {
        string hex = toHex(n * n);
        string hexatrigesimal = toHexatrigesimal(n * n * n);
        return hex + hexatrigesimal;
    }

    string toHex(int num) {
        string hex = "";
        string hexMap = "0123456789ABCDEF";
        if (num == 0) return "0";
        while (num > 0) {
            hex = hexMap[num % 16] + hex;
            num /= 16;
        }
        return hex;
    }

    string toHexatrigesimal(int num) {
        string hexatrigesimal = "";
        string hexatrigesimalMap = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
        if (num == 0) return "0";
        while (num > 0) {
            hexatrigesimal = hexatrigesimalMap[num % 36] + hexatrigesimal;
            num /= 36;
        }
        return hexatrigesimal;
    }
};
